      "deeperQuestionText": "Why is it technically incorrect for an electrician to say a cable drum 'weighs 100kg' when calculating the stress on a support bracket?",
      "deeperAnswerGuidance": [
        "Kilograms measure mass, not force",
        "Weight is a force measured in Newtons",
        "The bracket must support the downward pull of gravity (9.81)",
        "The actual force on the bracket is 981N, not 100 units of force"
      ],
      "hint": "Remember: Mass is the 'stuff' in kg; Weight is the 'pull' in Newtons. Always multiply by 9.81."
    },
    {
      "title": "Mechanical Systems",
      "basicQuestions": [
        {
          "questionText": "In a Class I lever, such as a pair of pliers, what is positioned in the middle between the effort and the load?",
          "answerGuidance": [
            "Fulcrum",
            "Pivot point",
            "The center pin"
          ]
        },
        {
          "questionText": "Which class of lever places the load in the middle, between the fulcrum and the effort?",
          "answerGuidance": [
            "Class II Lever",
            "Class 2",
            "Example: conduit bender or wheelbarrow"
          ]
        },
        {
          "questionText": "What is the term for the trade-off where a machine allows you to move a large load using less effort?",
          "answerGuidance": [
            "Mechanical advantage",
            "Trading distance for force",
            "Reducing required effort"
          ]
        }
      ],
      "deeperQuestionText": "How does the layout of a Class II lever specifically benefit an electrician using a conduit bender to bend steel pipe?",
      "deeperAnswerGuidance": [
        "The load (the pipe) is between the pivot and the effort",
        "It provides mechanical advantage to overcome the resistance of the steel",
        "It allows the user to apply less force over a longer handle to move a heavy load",
        "It multiplies the input force at the point of the bend"
      ],
      "hint": "Think about what is in the middle: Class I is the Pivot, Class II is the Load, and Class III is the Effort."
    }
  ]
}

